{
  "children": [
    {
      "name": "ParseCommand",
      "purpose": "Extract and validate the command field from the input JSON",
      "behavior": "Parse the input JSON to extract the 'command' field and validate it is one of the allowed commands (send, history, create_channel, join). Return the command and remaining payload.",
      "boundary": {
        "in_scope": [
          "JSON parsing",
          "command validation"
        ],
        "out_of_scope": [
          "executing the command",
          "data store access"
        ]
      },
      "semantic_inputs": [
        "input: Any - JSON with command field"
      ],
      "semantic_outputs": [
        "command: str - validated command",
        "payload: dict - remaining JSON fields"
      ],
      "preconditions": [
        "Input is valid JSON"
      ],
      "postconditions": [
        "Command is one of the allowed values"
      ],
      "guarantees": [
        "Returns error if command is missing or invalid"
      ],
      "composition_role": "transform",
      "stop_decompose": false,
      "stop_reason": "",
      "call_inputs": [
        {
          "name": "input",
          "type": "dict",
          "description": "Raw JSON input from parent",
          "source": "parent input"
        }
      ],
      "internal_leaf_accesses": [],
      "outputs": [
        {
          "name": "command",
          "type": "str",
          "description": "Validated command string",
          "consumer": "parent"
        },
        {
          "name": "payload",
          "type": "dict",
          "description": "Remaining JSON fields after command extraction",
          "consumer": "parent"
        }
      ],
      "signature": "def ParseCommand(input: dict) -> tuple[str, dict]"
    },
    {
      "name": "SendMessage",
      "purpose": "Handle sending a message to a channel",
      "behavior": "Validate that the user is a member of the specified channel, then store the message in the messages data store with timestamp and user info.",
      "boundary": {
        "in_scope": [
          "message validation",
          "channel membership check",
          "message storage"
        ],
        "out_of_scope": [
          "command parsing",
          "history retrieval"
        ]
      },
      "semantic_inputs": [
        "payload: dict - contains channel, user, and message content"
      ],
      "semantic_outputs": [
        "result: dict - success or error response"
      ],
      "preconditions": [
        "User is member of the channel",
        "Message content is non-empty"
      ],
      "postconditions": [
        "Message is stored in messages data store"
      ],
      "guarantees": [
        "Returns error if user not in channel"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": "",
      "call_inputs": [
        {
          "name": "payload",
          "type": "dict",
          "description": "Contains channel, user, and message content",
          "source": "parent input (from ParseCommand)"
        }
      ],
      "internal_leaf_accesses": [
        {
          "resource": "channels",
          "op": "read",
          "reason": "Check if user is a member of the channel"
        },
        {
          "resource": "messages",
          "op": "write",
          "reason": "Store the new message"
        }
      ],
      "outputs": [
        {
          "name": "result",
          "type": "dict",
          "description": "Success or error response",
          "consumer": "parent"
        }
      ],
      "signature": "def SendMessage(payload: dict) -> dict"
    },
    {
      "name": "GetHistory",
      "purpose": "Retrieve message history for a channel",
      "behavior": "Validate that the user is a member of the channel, then fetch the last 100 messages from the messages data store for that channel, ordered by timestamp.",
      "boundary": {
        "in_scope": [
          "channel membership check",
          "message retrieval",
          "limit enforcement"
        ],
        "out_of_scope": [
          "message sending",
          "channel creation"
        ]
      },
      "semantic_inputs": [
        "payload: dict - contains channel and user"
      ],
      "semantic_outputs": [
        "result: dict - list of messages or error"
      ],
      "preconditions": [
        "User is member of the channel"
      ],
      "postconditions": [
        "Returns at most 100 messages"
      ],
      "guarantees": [
        "Returns error if user not in channel"
      ],
      "composition_role": "query",
      "stop_decompose": false,
      "stop_reason": "",
      "call_inputs": [
        {
          "name": "payload",
          "type": "dict",
          "description": "Contains channel and user",
          "source": "parent input (from ParseCommand)"
        }
      ],
      "internal_leaf_accesses": [
        {
          "resource": "channels",
          "op": "read",
          "reason": "Check if user is a member of the channel"
        },
        {
          "resource": "messages",
          "op": "read",
          "reason": "Fetch messages for the channel"
        }
      ],
      "outputs": [
        {
          "name": "result",
          "type": "dict",
          "description": "List of messages or error",
          "consumer": "parent"
        }
      ],
      "signature": "def GetHistory(payload: dict) -> dict"
    },
    {
      "name": "CreateChannel",
      "purpose": "Create a new channel",
      "behavior": "Check that the channel name does not already exist, then create a new channel entry in the channels data store with the creator as the first member.",
      "boundary": {
        "in_scope": [
          "channel name uniqueness check",
          "channel creation",
          "initial membership"
        ],
        "out_of_scope": [
          "joining existing channels",
          "message operations"
        ]
      },
      "semantic_inputs": [
        "payload: dict - contains channel name and creator user"
      ],
      "semantic_outputs": [
        "result: dict - success or error response"
      ],
      "preconditions": [
        "Channel name does not already exist"
      ],
      "postconditions": [
        "Channel is created and creator is added as member"
      ],
      "guarantees": [
        "Returns error if channel already exists"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": "",
      "call_inputs": [
        {
          "name": "payload",
          "type": "dict",
          "description": "Contains channel name and creator user",
          "source": "parent input (from ParseCommand)"
        }
      ],
      "internal_leaf_accesses": [
        {
          "resource": "channels",
          "op": "read_write",
          "reason": "Check for existing channel and create new one"
        }
      ],
      "outputs": [
        {
          "name": "result",
          "type": "dict",
          "description": "Success or error response",
          "consumer": "parent"
        }
      ],
      "signature": "def CreateChannel(payload: dict) -> dict"
    },
    {
      "name": "JoinChannel",
      "purpose": "Add a user to an existing channel",
      "behavior": "Check that the channel exists and the user is not already a member, then add the user to the channel's member list in the channels data store.",
      "boundary": {
        "in_scope": [
          "channel existence check",
          "duplicate membership check",
          "membership update"
        ],
        "out_of_scope": [
          "channel creation",
          "message operations"
        ]
      },
      "semantic_inputs": [
        "payload: dict - contains channel name and user"
      ],
      "semantic_outputs": [
        "result: dict - success or error response"
      ],
      "preconditions": [
        "Channel exists",
        "User is not already a member"
      ],
      "postconditions": [
        "User is added to channel's member list"
      ],
      "guarantees": [
        "Returns error if channel does not exist or user already member"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": "",
      "call_inputs": [
        {
          "name": "payload",
          "type": "dict",
          "description": "Contains channel name and user",
          "source": "parent input (from ParseCommand)"
        }
      ],
      "internal_leaf_accesses": [
        {
          "resource": "channels",
          "op": "read_write",
          "reason": "Check channel existence and membership, then update member list"
        }
      ],
      "outputs": [
        {
          "name": "result",
          "type": "dict",
          "description": "Success or error response",
          "consumer": "parent"
        }
      ],
      "signature": "def JoinChannel(payload: dict) -> dict"
    }
  ],
  "interface_preservation": {
    "parent_inputs_covered_by": {
      "input": "ParseCommand"
    },
    "parent_outputs_produced_by": {
      "output": "SendMessage, GetHistory, CreateChannel, JoinChannel"
    }
  },
  "dataflow_edges": [
    {
      "from_node": "parent",
      "from_output": "input",
      "to_node": "ParseCommand",
      "to_input": "input",
      "note": "Pass raw input for command extraction"
    },
    {
      "from_node": "ParseCommand",
      "from_output": "command",
      "to_node": "parent",
      "to_input": "command",
      "note": "Return validated command for routing"
    },
    {
      "from_node": "ParseCommand",
      "from_output": "payload",
      "to_node": "parent",
      "to_input": "payload",
      "note": "Return remaining payload for command execution"
    },
    {
      "from_node": "parent",
      "from_output": "payload",
      "to_node": "SendMessage",
      "to_input": "payload",
      "note": "Pass payload when command is 'send'"
    },
    {
      "from_node": "parent",
      "from_output": "payload",
      "to_node": "GetHistory",
      "to_input": "payload",
      "note": "Pass payload when command is 'history'"
    },
    {
      "from_node": "parent",
      "from_output": "payload",
      "to_node": "CreateChannel",
      "to_input": "payload",
      "note": "Pass payload when command is 'create_channel'"
    },
    {
      "from_node": "parent",
      "from_output": "payload",
      "to_node": "JoinChannel",
      "to_input": "payload",
      "note": "Pass payload when command is 'join'"
    },
    {
      "from_node": "SendMessage",
      "from_output": "result",
      "to_node": "parent",
      "to_input": "output",
      "note": "Return success/error response"
    },
    {
      "from_node": "GetHistory",
      "from_output": "result",
      "to_node": "parent",
      "to_input": "output",
      "note": "Return messages or error"
    },
    {
      "from_node": "CreateChannel",
      "from_output": "result",
      "to_node": "parent",
      "to_input": "output",
      "note": "Return success/error response"
    },
    {
      "from_node": "JoinChannel",
      "from_output": "result",
      "to_node": "parent",
      "to_input": "output",
      "note": "Return success/error response"
    }
  ],
  "interface_audit": {
    "identity_preservation_detail": "All five child names (ParseCommand, SendMessage, GetHistory, CreateChannel, JoinChannel) are preserved exactly as in Stage 1. No children were added, deleted, renamed, or reordered.",
    "semantic_preservation_detail": "All Stage 1 fields (purpose, behavior, boundary, preconditions, postconditions, guarantees, composition_role) are copied verbatim without modification.",
    "call_signature_detail": "Each child's signature contains only call_inputs parameters. ParseCommand takes 'input' from parent. All command handlers take 'payload' from parent. No internal resources appear in signatures.",
    "internal_leaf_separation_detail": "Data store accesses (channels, messages) are listed under internal_leaf_accesses, not call_inputs. This ensures the parent does not need to pass data stores as parameters.",
    "dataflow_schema_detail": "All dataflow edges use only 'parent' or exact child names as from_node/to_node. No resource names (raw_data, processed_data, channels, messages, orders, inventory, payments) appear as endpoints.",
    "final_status": "ok"
  }
}
